// Port is open - try adb connect
output, err := exec.Command(ADB_PATH, "connect", addr).CombinedOutput()
result := strings.TrimSpace(string(output))

if strings.Contains(result, "connected") || strings.Contains(result, "already") {
	// Get device serial/fingerprint to detect duplicates
	serialOutput, _ := exec.Command(ADB_PATH, "-s", addr, "shell", "getprop ro.build.fingerprint").CombinedOutput()
	serial := strings.TrimSpace(string(serialOutput))

	knownSerialsMutex.Lock()
	existingPort, isDuplicate := knownSerials[serial]
	knownSerialsMutex.Unlock()

	if isDuplicate && serial != "" {
		// This is a duplicate device on a different port
		fmt.Printf("[AUTOSCAN] Duplicate device detected: %s (already connected on %s, skipping %s)\n", serial, existingPort, addr)
		// Disconnect the duplicate
		exec.Command(ADB_PATH, "disconnect", addr).Run()
		continue
	}

	knownPortMutex.Lock()
	if !knownPorts[addr] {
		knownPorts[addr] = true
		if serial != "" {
			knownSerialsMutex.Lock()
			knownSerials[serial] = addr
			knownSerialsMutex.Unlock()
		}
		fmt.Printf("[AUTOSCAN] New emulator found and connected: %s\n", addr)

		// Publish event for notification
		PublishDeviceEvent("connected", addr, "Emulator", "device")
	}
	knownPortMutex.Unlock()
}
